const express = require('express');
const app = express();

app.use(express.json());

app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    console.log(`${req.method} ${req.path} ${res.statusCode} ${Date.now() - start}ms`);
  });
  next();
});

app.post('/users', async (req, res) => {
  const { name, email } = req.body;
  if (!name || typeof name !== 'string' || name.trim().length === 0 || name.length > 100) {
    return res.status(400).json({ error: 'name must be a non-empty string with max 100 characters' });
  }
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    return res.status(400).json({ error: 'email must be a valid email address' });
  }
  const result = await db('users').insert({ name, email });
  res.status(201).json({ id: result[0], name, email });
});

app.get('/users', async (req, res) => {
  const limit = Math.min(parseInt(req.query.limit) || 20, 100);
  const offset = parseInt(req.query.offset) || 0;
  const users = await db('users').limit(limit).offset(offset);
  const [{ count }] = await db('users').count('* as count');
  res.json({ users, total: parseInt(count), limit, offset });
});

app.get('/users/:id', async (req, res) => {
  const user = await db('users').where({ id: req.params.id }).first();
  if (!user) return res.status(404).json({ error: 'Not found' });
  res.json(user);
});

app.put('/users/:id', async (req, res) => {
  const { name, email } = req.body;
  await db('users').where({ id: req.params.id }).update({ name, email });
  res.json({ id: req.params.id, name, email });
});

app.patch('/users/:id', async (req, res) => {
  const updates = {};
  if (req.body.name !== undefined) {
    if (typeof req.body.name !== 'string' || req.body.name.trim().length === 0 || req.body.name.length > 100) {
      return res.status(400).json({ error: 'name must be a non-empty string with max 100 characters' });
    }
    updates.name = req.body.name;
  }
  if (req.body.email !== undefined) {
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(req.body.email)) {
      return res.status(400).json({ error: 'email must be a valid email address' });
    }
    updates.email = req.body.email;
  }
  if (Object.keys(updates).length === 0) {
    return res.status(400).json({ error: 'at least one of name or email must be provided' });
  }
  await db('users').where({ id: req.params.id }).update(updates);
  res.json({ id: req.params.id, ...updates });
});

app.delete('/users/:id', async (req, res) => {
  await db('users').where({ id: req.params.id }).del();
  res.status(204).send();
});

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: Date.now() });
});

module.exports = app;

